from zipfile import ZipFile
import xml.etree.ElementTree as ET

NS = {'m': 'http://schemas.openxmlformats.org/spreadsheetml/2006/main', 'r': 'http://schemas.openxmlformats.org/officeDocument/2006/relationships'}

def col_idx(cell_ref):
    letters = ''.join(ch for ch in cell_ref if ch.isalpha())
    idx = 0
    for ch in letters:
        idx = idx * 26 + ord(ch.upper()) - 64
    return idx - 1

def shared_strings(zf):
    if 'xl/sharedStrings.xml' not in zf.namelist():
        return []
    root = ET.fromstring(zf.read('xl/sharedStrings.xml'))
    return [''.join(t.text or '' for t in item.findall('.//m:t', NS)) for item in root.findall('m:si', NS)]

def sheet_path(zf, sheet_name):
    workbook = ET.fromstring(zf.read('xl/workbook.xml'))
    rels = ET.fromstring(zf.read('xl/_rels/workbook.xml.rels'))
    targets = {rel.attrib['Id']: rel.attrib['Target'] for rel in rels}
    for sheet in workbook.find('m:sheets', NS):
        if sheet.attrib['name'] == sheet_name:
            rel_id = sheet.attrib['{http://schemas.openxmlformats.org/officeDocument/2006/relationships}id']
            return 'xl/' + targets[rel_id]
    raise KeyError(sheet_name)

def cell_value(cell, strings):
    cell_type = cell.attrib.get('t')
    if cell_type == 'inlineStr':
        return ''.join(t.text or '' for t in cell.findall('.//m:t', NS))
    value = cell.find('m:v', NS)
    if value is None:
        return None
    raw = value.text or ''
    if cell_type == 's':
        return strings[int(raw)]
    if cell_type == 'b':
        return raw == '1'
    try:
        number = float(raw)
        return int(number) if number.is_integer() else number
    except ValueError:
        return raw

def read_sheet(path, sheet_name):
    with ZipFile(path) as zf:
        strings = shared_strings(zf)
        worksheet = ET.fromstring(zf.read(sheet_path(zf, sheet_name)))
        rows = []
        for row in worksheet.findall('.//m:sheetData/m:row', NS):
            values = {}
            max_col = -1
            for cell in row.findall('m:c', NS):
                idx = col_idx(cell.attrib['r'])
                values[idx] = cell_value(cell, strings)
                max_col = max(max_col, idx)
            if max_col >= 0:
                rows.append([values.get(i) for i in range(max_col + 1)])
        return rows

